package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testFormatWithNormalValues() throws Exception {
        String result = csvFormat.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    public void testFormatWithNullValue() throws Exception {
        String result = csvFormat.format("a", null, "c");
        assertEquals("a,,c", result);
    }

    @Test
    public void testFormatWithEmptyValues() throws Exception {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    public void testFormatThrowsIllegalStateExceptionOnIOException() throws Exception {
        // Since Mockito 3 doesn't support mockConstruction, use spy and override printRecord via reflection
        CSVFormat spyFormat = Mockito.spy(csvFormat);

        // Create a CSVPrinter spy that throws IOException on printRecord
        CSVPrinter printer = new CSVPrinter(new StringWriter(), spyFormat);
        CSVPrinter spyPrinter = Mockito.spy(printer);
        doThrow(new IOException("mock IO error")).when(spyPrinter).printRecord(any());

        // Use reflection to replace the CSVPrinter constructor call inside CSVFormat.format
        // We'll override CSVFormat.format to use our spyPrinter instead

        // Create an anonymous subclass to override format method
        CSVFormat faultyFormat = new CSVFormat(
                spyFormat.getDelimiter(),
                spyFormat.getQuoteCharacter(),
                spyFormat.getQuoteMode(),
                spyFormat.getCommentMarker(),
                spyFormat.getEscapeCharacter(),
                spyFormat.getIgnoreSurroundingSpaces(),
                spyFormat.getIgnoreEmptyLines(),
                spyFormat.getRecordSeparator(),
                spyFormat.getNullString(),
                spyFormat.getHeader(),
                spyFormat.getSkipHeaderRecord(),
                spyFormat.getAllowMissingColumnNames()) {
            @Override
            public String format(final Object... values) {
                try {
                    spyPrinter.printRecord(values);
                    return spyPrinter.toString().trim();
                } catch (final IOException e) {
                    throw new IllegalStateException(e);
                }
            }
        };

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            faultyFormat.format("a", "b");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("mock IO error", thrown.getCause().getMessage());
    }

    @Test
    public void testFormatTrimOutput() throws Exception {
        // Using reflection to create a CSVFormat instance with a recordSeparator that adds trailing spaces
        CSVFormat customFormat = CSVFormat.DEFAULT.withRecordSeparator(" \n");
        String result = customFormat.format("a", "b");
        assertEquals("a,b", result);
    }

    @Test
    public void testFormatWithVariousObjects() throws Exception {
        Object[] values = { 1, 2.5, true, 'c', new Object() {
            @Override
            public String toString() {
                return "obj";
            }
        }};
        String result = csvFormat.format(values);
        // The result should contain string representations separated by commas
        assertTrue(result.startsWith("1,2.5,true,c,"));
        assertTrue(result.endsWith("obj"));
    }
}
